mapper.select:
/* SQL ID : SrvyPtcpDAO.srvyPtcpList 설 명 : 설문참여목록 */ SELECT ROW_NUMBER() OVER(ORDER BY A.USERNM) AS LINE_NO , A.* , CASE WHEN A.PTCP_DTTM IS NULL THEN 'NOPTCP' WHEN A.PTCPYN = 'Y' THEN 'COMPLETED' END AS PTCP_GBNCD FROM ( WITH SUB_SRVY AS ( SELECT SRVY_ID FROM TB_LMS_SRVY WHERE DELYN = 'N' AND USEYN = 'Y' AND (UP_SRVY_ID = #{srvyId} OR SRVY_ID = #{srvyId}) ), TEAM AS ( SELECT SRVY_TRGT.SRVY_ID , TEAM.TEAM_ID , TEAM.TEAMNM , TEAM_MBR.USER_ID , TEAM_MBR.LDRYN FROM TB_LMS_TEAM TEAM JOIN TB_LMS_SRVY_TRGT SRVY_TRGT ON TEAM.TEAM_ID = SRVY_TRGT.TEAM_ID JOIN TB_LMS_TEAM_MBR TEAM_MBR ON TEAM.TEAM_ID = TEAM_MBR.TEAM_ID WHERE TEAM.TEAM_CPST_CMPTNYN = 'Y' AND SRVY_TRGT.SRVY_ID IN (SELECT SRVY_ID FROM SUB_SRVY) ), PTCP AS ( SELECT PTCP.* FROM TB_LMS_SRVY_PTCP PTCP WHERE PTCP.SRVY_ID IN (SELECT SRVY_ID FROM SUB_SRVY) ) SELECT ATNDLC.SBJCT_ID , TM.TEAM_ID , TM.TEAMNM , NVL((SELECT DEPTNM FROM TB_LMS_DEPT WHERE ORG_ID = USR.ORG_ID AND DEPT_ID = USR.DEPT_ID),'-') AS DEPTNM , NVL(USR.STDNT_NO,'-') AS STDNT_NO , (SELECT CNTCT FROM TB_LMS_USER_CNTCT WHERE CNTCT_TYCD = 'MBL_PHN' AND USER_ID = ATNDLC.USER_ID) AS MOBILE_NO , (SELECT CNTCT FROM TB_LMS_USER_CNTCT WHERE CNTCT_TYCD = 'INDV_EML' AND USER_ID = ATNDLC.USER_ID) AS EMAIL , ATNDLC.USER_ID , USR.USER_RPRS_ID , USR.USERNM , TM.LDRYN , CASE WHEN TM.TEAM_ID IS NOT NULL THEN TM.SRVY_ID ELSE NVL(PTCP_INDI.SRVY_ID, SRVY.SRVY_ID) END SRVY_ID , CASE WHEN TM.TEAM_ID IS NOT NULL THEN PTCP_TEAM.SRVY_PTCP_ID ELSE PTCP_INDI.SRVY_PTCP_ID END AS SRVY_PTCP_ID , NVL(CASE WHEN TM.TEAM_ID IS NOT NULL THEN PTCP_TEAM.PTCP_EVL_SCR ELSE PTCP_INDI.PTCP_EVL_SCR END, 0) AS PTCP_EVL_SCR , CASE WHEN TM.TEAM_ID IS NOT NULL THEN PTCP_TEAM.PTCP_DTTM ELSE PTCP_INDI.PTCP_DTTM END AS PTCP_DTTM , NVL(CASE WHEN TM.TEAM_ID IS NOT NULL THEN CASE WHEN PTCP_TEAM.PTCP_DTTM IS NOT NULL THEN 'Y' ELSE 'N' END ELSE CASE WHEN PTCP_INDI.PTCP_DTTM IS NOT NULL THEN 'Y' ELSE 'N' END END,'N') AS PTCPYN , NVL(CASE WHEN TM.TEAM_ID IS NOT NULL THEN PTCP_TEAM.SRVY_PTCP_EVLYN ELSE PTCP_INDI.SRVY_PTCP_EVLYN END,'N') AS SRVY_PTCP_EVLYN FROM TB_LMS_ATNDLC ATNDLC JOIN TB_LMS_SRVY SRVY ON ATNDLC.SBJCT_ID = SRVY.SBJCT_ID AND SRVY.USEYN = 'Y' AND SRVY.DELYN = 'N' JOIN TB_LMS_USER USR ON ATNDLC.USER_ID = USR.USER_ID AND USR.USER_ID_STSCD = 'APRV_CMPTN' AND USR.USER_TYCD = 'STDNT' LEFT JOIN TEAM TM ON TM.USER_ID = ATNDLC.USER_ID LEFT JOIN PTCP PTCP_TEAM ON PTCP_TEAM.SRVY_ID = TM.SRVY_ID AND PTCP_TEAM.USER_ID = ATNDLC.USER_ID LEFT JOIN PTCP PTCP_INDI ON PTCP_INDI.USER_ID = ATNDLC.USER_ID AND PTCP_INDI.SRVY_ID = SRVY.SRVY_ID WHERE ATNDLC.AUDITYN = 'N' AND ATNDLC.ATNDLC_STSCD = 'ATNDLC' AND SRVY.SRVY_ID = #{srvyId}
AND USR.USER_ID = #{userId}
) A
AND A.PTCPYN = #{ptcpyn}
AND A.SRVY_PTCP_EVLYN = #{srvyPtcpEvlyn}
AND ( LOWER(A.DEPTNM) LIKE FN_LIKE_VAL(LOWER(#{searchValue})) OR LOWER(A.STDNT_NO) LIKE FN_LIKE_VAL(LOWER(#{searchValue})) OR LOWER(A.USERNM) LIKE FN_LIKE_VAL(LOWER(#{searchValue})) )

mapper.update:
/* SQL ID : SrvyPtcpDAO.userListEvlScrBulkModify 설 명 : 사용자목록평가점수일괄수정 */ MERGE INTO TB_LMS_SRVY_PTCP SRVY_PTCP USING (
SELECT #{item.srvyPtcpId} AS SRVY_PTCP_ID , #{item.srvyId} AS SRVY_ID , #{item.userId} AS USER_ID , TO_NUMBER(#{item.scr}) AS PTCP_EVL_SCR , #{item.scoreType} AS SCORE_TYPE , #{item.rgtrId} AS RGTR_ID FROM DUAL
) USR ON ( SRVY_PTCP.SRVY_PTCP_ID = USR.SRVY_PTCP_ID AND SRVY_PTCP.USER_ID = USR.USER_ID ) WHEN MATCHED THEN UPDATE SET SRVY_PTCP.PTCP_EVL_SCR = CASE WHEN USR.SCORE_TYPE = 'addition' THEN CASE WHEN NVL(SRVY_PTCP.PTCP_EVL_SCR, 0.0) + USR.PTCP_EVL_SCR < 0.0 THEN 0.0 WHEN NVL(SRVY_PTCP.PTCP_EVL_SCR, 0.0) + USR.PTCP_EVL_SCR > 100.0 THEN 100.0 ELSE NVL(SRVY_PTCP.PTCP_EVL_SCR, 0.0) + USR.PTCP_EVL_SCR END ELSE USR.PTCP_EVL_SCR END , SRVY_PTCP.SRVY_PTCP_EVLYN = 'Y' , SRVY_PTCP.MDFR_ID = USR.RGTR_ID , SRVY_PTCP.MOD_DTTM = FN_DTTM() WHEN NOT MATCHED THEN INSERT ( SRVY_PTCP_ID , SRVY_ID , USER_ID , PTCP_EVL_SCR , SRVY_PTCP_EVLYN , RGTR_ID , REG_DTTM ) VALUES ( USR.SRVY_PTCP_ID , USR.SRVY_ID , USR.USER_ID , CASE WHEN USR.PTCP_EVL_SCR < 0 THEN 0 ELSE USR.PTCP_EVL_SCR END , 'Y' , USR.RGTR_ID , FN_DTTM() )
